mermaid:
classDiagram
    class ParkingLot {
        -floors : List
        -activeTickets : Map
        -pricingStrategy : PricingStrategy
        +getInstance() ParkingLot
        +parkVehicle(Vehicle) Ticket
        +unparkVehicle(String) Payment
        +getAvailability() Map
    }
    class ParkingFloor {
        -floorNumber : int
        -spots : List
        +findAvailableSpot(Vehicle) ParkingSpot
        +getAvailableCount(SpotType) int
    }
    class ParkingSpot {
        -spotId : String
        -type : SpotType
        -isAvailable : boolean
        -currentVehicle : Vehicle
        +assignVehicle(Vehicle) void
        +removeVehicle() Vehicle
    }
    class Vehicle {
        -licensePlate : String
        -type : VehicleType
        -color : String
        +canFitInSpot(SpotType) boolean
    }
    class Car {
        +canFitInSpot(SpotType) boolean
    }
    class Truck {
        +canFitInSpot(SpotType) boolean
    }
    class Motorcycle {
        +canFitInSpot(SpotType) boolean
    }
    class Ticket {
        -ticketId : String
        -vehicle : Vehicle
        -spot : ParkingSpot
        -entryTime : LocalDateTime
        +calculateDurationHours() long
        +markExit() void
        +markPaid() void
    }
    class Payment {
        -ticket : Ticket
        -amount : double
        -method : PaymentMethod
    }
    class PricingStrategy {
        +calculatePrice(Ticket) double
    }
    class HourlyPricingStrategy {
        -hourlyRates : Map
        +calculatePrice(Ticket) double
    }
    ParkingLot *-- ParkingFloor
    ParkingFloor *-- ParkingSpot
    ParkingSpot o-- Vehicle
    Vehicle <|-- Car
    Vehicle <|-- Truck
    Vehicle <|-- Motorcycle
    ParkingLot --> PricingStrategy
    PricingStrategy <|.. HourlyPricingStrategy
    Ticket --> ParkingSpot
    Ticket --> Vehicle
    Payment --> Ticket
